"use client";

import { useEffect, useState } from "react";
import { Invoice, PurchaseOrder, Vendor } from "@/types";
import { getInvoices, createInvoice, updateInvoiceStatus } from "@/lib/invoices";
import { getPurchaseOrders } from "@/lib/purchaseOrders";
import { getVendors } from "@/lib/vendors";

export default function InvoicesPage() {
    // Data State
    const [invoices, setInvoices] = useState<Invoice[]>([]);
    const [pos, setPos] = useState<PurchaseOrder[]>([]);
    const [vendors, setVendors] = useState<Vendor[]>([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);

    // Form State
    const [formData, setFormData] = useState({
        poId: "",
        invoiceNumber: "",
        amount: 0,
        issueDate: new Date().toISOString().split('T')[0],
        dueDate: new Date().toISOString().split('T')[0]
    });

    const fetchData = async () => {
        setLoading(true);
        const [invData, poData, vendorData] = await Promise.all([
            getInvoices(),
            getPurchaseOrders(),
            getVendors()
        ]);
        setInvoices(invData.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime()));
        setPos(poData);
        setVendors(vendorData);
        setLoading(false);
    };

    useEffect(() => {
        fetchData();
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const selectedPO = pos.find(p => p.id === formData.poId);
            // Validations
            if (!selectedPO) {
                alert("Please select a valid Purchase Order");
                return;
            }

            // 3-Way Match Check (Simplified for now: Check Amount)
            if (formData.amount > selectedPO.totalAmount) {
                if (!confirm(`Warning: Invoice amount ($${formData.amount}) exceeds PO amount ($${selectedPO.totalAmount}). Continue?`)) return;
            }

            await createInvoice({
                vendorId: selectedPO.vendorId,
                vendorName: selectedPO.vendorName,
                poId: selectedPO.id,
                poNumber: selectedPO.poNumber,
                invoiceNumber: formData.invoiceNumber,
                amount: formData.amount,
                issueDate: new Date(formData.issueDate),
                dueDate: new Date(formData.dueDate),
                status: 'PENDING'
            });

            setShowModal(false);
            setFormData({ poId: "", invoiceNumber: "", amount: 0, issueDate: "", dueDate: "" });
            fetchData();
        } catch (error) {
            alert("Error creating invoice");
        }
    };

    const handlePay = async (id: string) => {
        if (!confirm("Mark this invoice as PAID?")) return;
        await updateInvoiceStatus(id, 'PAID');
        fetchData();
    };

    if (loading) return <div>Loading Invoices...</div>;

    return (
        <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <h1 style={{ fontSize: '1.875rem', fontWeight: 'bold', color: 'var(--primary)' }}>Invoices</h1>
                <button className="btn btn-primary" onClick={() => setShowModal(true)}>+ Record Invoice</button>
            </div>

            {showModal && (
                <div style={{ position: 'fixed', inset: 0, backgroundColor: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 50 }}>
                    <div className="card" style={{ width: '500px', maxWidth: '90%' }}>
                        <h2 style={{ fontSize: '1.25rem', fontWeight: 'bold', marginBottom: '1rem' }}>Record Vendor Invoice</h2>
                        <form onSubmit={handleSubmit}>
                            <div style={{ marginBottom: '1rem' }}>
                                <label style={{ display: 'block', marginBottom: '0.5rem' }}>Select Purchase Order</label>
                                <select
                                    style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                    value={formData.poId}
                                    onChange={e => {
                                        const selectedPO = pos.find(p => p.id === e.target.value);
                                        setFormData({
                                            ...formData,
                                            poId: e.target.value,
                                            // Auto-generate Invoice # based on PO #
                                            invoiceNumber: selectedPO ? `INV-${selectedPO.poNumber}` : ""
                                        });
                                    }}
                                    required
                                >
                                    <option value="">-- Select PO --</option>
                                    {pos.filter(p => p.status !== 'CLOSED').map(po => (
                                        <option key={po.id} value={po.id}>
                                            {po.poNumber} — {po.vendorName} (${po.totalAmount})
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem' }}>Invoice #</label>
                                    <input type="text" required style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.invoiceNumber} onChange={e => setFormData({ ...formData, invoiceNumber: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem' }}>Amount</label>
                                    <input type="number" step="0.01" required style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.amount} onChange={e => setFormData({ ...formData, amount: Number(e.target.value) })} />
                                </div>
                            </div>

                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1.5rem' }}>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem' }}>Issue Date</label>
                                    <input type="date" required style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.issueDate} onChange={e => setFormData({ ...formData, issueDate: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem' }}>Due Date</label>
                                    <input type="date" required style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.dueDate} onChange={e => setFormData({ ...formData, dueDate: e.target.value })} />
                                </div>
                            </div>

                            <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end' }}>
                                <button type="button" className="btn" onClick={() => setShowModal(false)}>Cancel</button>
                                <button type="submit" className="btn btn-primary">Save Invoice</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {invoices.length === 0 ? (
                <div className="card" style={{ textAlign: 'center', padding: '3rem' }}>
                    <p style={{ color: 'var(--text-secondary)' }}>No Invoices recorded yet.</p>
                </div>
            ) : (
                <div className="card" style={{ overflowX: 'auto', padding: 0 }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
                        <thead style={{ backgroundColor: 'var(--background)', borderBottom: '1px solid var(--border)' }}>
                            <tr>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Status</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Invoice #</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>PO #</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Vendor</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Due Date</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Amount</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            {invoices.map((inv) => (
                                <tr key={inv.id} style={{ borderBottom: '1px solid var(--border)' }}>
                                    <td style={{ padding: '1rem' }}>
                                        <span style={{
                                            padding: '0.25rem 0.5rem',
                                            borderRadius: '999px',
                                            fontSize: '0.75rem',
                                            backgroundColor: inv.status === 'PAID' ? '#dcfce7' : '#fee2e2',
                                            color: inv.status === 'PAID' ? '#166534' : '#991b1b'
                                        }}>
                                            {inv.status}
                                        </span>
                                    </td>
                                    <td style={{ padding: '1rem', fontWeight: 600 }}>{inv.invoiceNumber}</td>
                                    <td style={{ padding: '1rem' }}>{inv.poNumber}</td>
                                    <td style={{ padding: '1rem' }}>{inv.vendorName}</td>
                                    <td style={{ padding: '1rem' }}>{inv.dueDate.toLocaleDateString()}</td>
                                    <td style={{ padding: '1rem', fontWeight: 600 }}>${inv.amount.toFixed(2)}</td>
                                    <td style={{ padding: '1rem' }}>
                                        {inv.status !== 'PAID' && inv.id && (
                                            <button
                                                onClick={() => inv.id && handlePay(inv.id)}
                                                style={{ color: 'var(--success)', background: 'none', border: '1px solid var(--success)', padding: '0.25rem 0.5rem', borderRadius: '4px', cursor: 'pointer', fontSize: '0.8rem' }}
                                            >
                                                Mark Paid
                                            </button>
                                        )}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
    );
}
