import { db } from "./firebase";
import { ref, push, set, get, child, update } from "firebase/database";
import { Invoice } from "@/types";

const COLLECTION_NAME = "invoices";

export const createInvoice = async (invoice: Omit<Invoice, 'id' | 'createdAt'>) => {
    try {
        const invRef = ref(db, COLLECTION_NAME);
        const newInvRef = push(invRef);

        await set(newInvRef, {
            ...invoice,
            issueDate: invoice.issueDate.toISOString(),
            dueDate: invoice.dueDate.toISOString(),
            createdAt: new Date().toISOString(),
            status: 'PENDING'
        });

        return newInvRef.key;
    } catch (error) {
        console.error("Error creating invoice: ", error);
        throw error;
    }
};

export const getInvoices = async (): Promise<Invoice[]> => {
    try {
        const dbRef = ref(db);
        const snapshot = await get(child(dbRef, COLLECTION_NAME));

        if (snapshot.exists()) {
            const data = snapshot.val();
            return Object.entries(data).map(([key, v]: [string, any]) => ({
                id: key,
                ...v,
                issueDate: new Date(v.issueDate),
                dueDate: new Date(v.dueDate),
                createdAt: new Date(v.createdAt),
            })) as Invoice[];
        }
        return [];
    } catch (error) {
        console.error("Error fetching invoices", error);
        return [];
    }
};

export const updateInvoiceStatus = async (invId: string, status: 'PAID') => {
    const invRef = ref(db, `${COLLECTION_NAME}/${invId}`);
    await update(invRef, { status });
};
